ICON_EMOJI_FALLBACK = {
    'book': '📖', 'book-open': '📖', 'zap': '⚡', 'star': '⭐',
    'sword': '⚔️', 'shield': '🛡️', 'crown': '👑', 'flame': '🔥',
    'gem': '💎', 'scroll': '📜', 'wand': '🪄', 'sparkles': '✨',
    'hat-wizard': '🧙', 'brain': '🧠', 'code': '💻', 'binary': '🔢',
    'layers': '📚', 'target': '🎯', 'trophy': '🏆',
    'lock': '🔒', 'check-circle': '✅', 'circle': '⭕',
    'chevron-right': '▶', 'arrow-left': '◀',
}


@register.simple_tag
def grimoire_icon(icon_name, size=24, classes=''):
    svg = LUCIDE_ICONS.get(icon_name)
    if svg:
        svg = svg.replace('width="24"', f'width="{size}"').replace('height="24"', f'height="{size}"')
        if classes:
            svg = svg.replace('<svg', f'<svg class="{classes}"')
        return mark_safe(svg)
    emoji = ICON_EMOJI_FALLBACK.get(icon_name, '📖')
    return mark_safe(f'<span class="grimorio-icon-fallback {classes}" style="font-size:{size}px" aria-hidden="true">{emoji}</span>')


@register.simple_tag
def spell_status_icon(status, size=20):
    icons = {
        'completed': ('check-circle', '#22c55e'),
        'blocked': ('lock', '#8b7db8'),
        'in_progress': ('circle', '#a78bfa'),
    }
    icon_name, color = icons.get(status, ('circle', '#8b7db8'))
    svg = LUCIDE_ICONS.get(icon_name, LUCIDE_ICONS['circle'])
    svg = svg.replace('width="24"', f'width="{size}"').replace('height="24"', f'height="{size}"')
    svg = svg.replace('stroke="currentColor"', f'stroke="{color}"')
    return mark_safe(svg)
